1	/**
2	 * Bot-to-Bot Relay — dual transport: Upstash Redis + Telegram bot-to-bot.
3	 *
4	 * Architecture:
5	 *   sendRelay(msg) -> transport switch:
6	 *     "redis"    -> LPUSH to Redis list "relay:<targetBot>"
7	 *     "telegram" -> bot.api.sendMessage(@targetBotUsername, text)
8	 *     "both"     -> telegram first, redis as fallback
9	 *   + sendMessage to group (mirror)
10	 *
11	 *   Incoming:
12	 *     Redis poller -> RPOP from "relay:<myName>" -> inject handler
13	 *     Bot handler  -> from.is_bot + allowedBotIds -> inject handler
14	 *
15	 * Redis-only incoming relay messages are mirrored by commands/relay.ts after
16	 * transport de-duplication. Telegram relay uses sender-side group mirrors so
17	 * each conversational message appears once in the shared group.
18	 */
19	import { stat } from "node:fs/promises";
20	import { createHash } from "node:crypto";
21	import path from "node:path";
22	import { InputFile, type Bot } from "grammy";
23	import { config } from "./config.js";
24	import {
25	  getRelayPeer, listRelayPeerNames, relayPeersFileExists,
26	} from "./relayPeers.js";
27	
28	export type RelayTransport = "redis" | "telegram" | "both";
29	
30	/** 環路防護上限（Q7）：hop > MAX_HOP 拒發/拒收。 */
31	export const MAX_HOP = 3;
32	
33	export type RelaySendResult =
34	  | { ok: true; transport: "telegram" | "redis" }
35	  | { ok: false; error: string };
36	
37	export interface RelayConfig {
38	  redisUrl: string;
39	  redisToken: string;
40	  groupChatId: number;
41	  botName: string;
42	  transport: RelayTransport;
43	  targetBotUsername: string; // e.g. "@RK_AI_Codex_bot" for telegram transport
44	  /** 多 peer 對照表：peer 名 → Telegram username。未設定沿用 targetBotUsername。 */
45	  peerUsernames?: Record<string, string>;
46	  maxConsecutiveTurns: number;
47	}
48	
49	interface RelayMessage {
50	  from: string;
51	  text: string;
52	  ts: string;
53	  /** re-relay 計數（Q7）；缺欄位視為 1（容忍舊版 peer）。 */
54	  hop?: number;
55	}
