57	let cfg: RelayConfig | null = null;
58	let bot: Bot | null = null;
59	let pollTimer: ReturnType<typeof setInterval> | null = null;
60	let heartbeatTimer: ReturnType<typeof setInterval> | null = null;
61	let onIncoming: ((msg: RelayMessage) => void) | null = null;
62	let idleCount = 0;
63	const IDLE_MAX = 40; // ~2 min at 3s interval -> auto-stop
64	const HEARTBEAT_MS = 30_000; // low-freq check for unsolicited incoming
65	const IMG_EXT = new Set([".jpg", ".jpeg", ".png", ".gif", ".webp", ".bmp"]);
66	const PHOTO_MAX_BYTES = 10 * 1024 * 1024;
