68	export interface RelayRuntimeStatus {
69	  configured: boolean;
70	  botName: string | null;
71	  transport: RelayTransport | null;
72	  transportLabel: string;
73	  groupChatId: number | null;
74	  targetBotUsername: string | null;
75	  redisConfigured: boolean;
76	  telegramConfigured: boolean;
77	  redisPollerExpected: boolean;
78	  redisPollerActive: boolean;
79	  heartbeatActive: boolean;
80	  maxConsecutiveTurns: number | null;
81	}
