83	export function describeRelayTransport(transport: RelayTransport | null): string {
84	  if (transport === "redis") return "redis only";
85	  if (transport === "telegram") return "telegram only";
86	  if (transport === "both") return "telegram primary + redis fallback";
87	  return "not configured";
88	}
89	
90	export function getRelayRuntimeStatus(): RelayRuntimeStatus {
91	  if (!cfg) {
92	    return {
93	      configured: false,
94	      botName: null,
95	      transport: null,
96	      transportLabel: describeRelayTransport(null),
97	      groupChatId: null,
98	      targetBotUsername: null,
99	      redisConfigured: false,
100	      telegramConfigured: false,
101	      redisPollerExpected: false,
102	      redisPollerActive: false,
103	      heartbeatActive: false,
104	      maxConsecutiveTurns: null,
105	    };
106	  }
107	  const redisConfigured = !!(cfg.redisUrl && cfg.redisToken);
108	  const telegramConfigured = !!cfg.targetBotUsername;
109	  return {
110	    configured: true,
111	    botName: cfg.botName,
112	    transport: cfg.transport,
113	    transportLabel: describeRelayTransport(cfg.transport),
114	    groupChatId: cfg.groupChatId,
115	    targetBotUsername: cfg.targetBotUsername || null,
116	    redisConfigured,
117	    telegramConfigured,
118	    redisPollerExpected: cfg.transport !== "telegram" && redisConfigured,
119	    redisPollerActive: !!pollTimer,
120	    heartbeatActive: !!heartbeatTimer,
121	    maxConsecutiveTurns: cfg.maxConsecutiveTurns,
122	  };
123	}
