129	function isUnderAllowedRoot(abs: string): boolean {
130	  const roots = [config.sessionCwd, ...config.sendFileRoots];
131	  const normAbs = path.resolve(abs).toLowerCase();
132	  return roots.some((root) => {
133	    const r = path.resolve(root).toLowerCase().replace(/[\\/]+$/, "");
134	    if (normAbs === r) return true;
135	    return normAbs.startsWith(r + "\\") || normAbs.startsWith(r + "/");
136	  });
137	}
