139	async function redisCommand(command: string[], c: RelayConfig | null = cfg): Promise<{ result: unknown }> {
140	  if (!c) throw new Error("Relay not initialized");
141	  const res = await fetch(c.redisUrl, {
142	    method: "POST",
143	    headers: {
144	      Authorization: `Bearer ${c.redisToken}`,
145	      "Content-Type": "application/json",
146	    },
147	    body: JSON.stringify(command),
148	  });
149	  if (!res.ok) {
150	    const body = await res.text();
151	    throw new Error(`Redis ${command[0]} failed: ${res.status} ${body}`);
152	  }
153	  return res.json() as Promise<{ result: unknown }>;
154	}
