156	/**
157	 * Resolve a relay peer 的 Telegram username（telegram transport 用）。
158	 * 沒設 peerUsernames map → 沿用單一 targetBotUsername（既有單 peer 行為）；
159	 * 有設 map 但 peer 不在其中 → null（拒走 telegram，避免寫給 peer B 的訊息
160	 * 靜默誤投給預設 bot；transport=both 時自然 fallback 到 redis 正確投遞）。
161	 */
162	function resolvePeerUsername(targetBot: string): string | null {
163	  if (!cfg) return null;
164	  const map = cfg.peerUsernames;
165	  if (map && Object.keys(map).length > 0) {
166	    return map[targetBot] ?? null;
167	  }
168	  return cfg.targetBotUsername || null;
169	}
