171	/** Start polling if not already running. */
172	export function ensurePollerRunning(): void {
173	  if (pollTimer || !cfg) return;
174	  idleCount = 0;
175	  pollTimer = setInterval(poll, 3000);
176	  console.log(`[relay] poller activated`);
177	}
