179	/**
180	 * Resolve outgoing destination for a target peer name.
181	 * peers.json 存在 → 查 peer config（未知/disabled 回 error）；
182	 * 不存在 → legacy 單 peer env mode（沿用 RELAY_TARGET_BOT_USERNAME）。
183	 */
184	function resolveOutgoing(targetBot: string): { username: string; mirrorGroupId: number } | { error: string } {
185	  if (!cfg) return { error: "Relay not initialized" };
186	  if (relayPeersFileExists()) {
187	    const peer = getRelayPeer(targetBot);
188	    if (!peer) {
189	      const names = listRelayPeerNames();
190	      return { error: `未知 peer「${targetBot}」，可用：${names.join("、") || "(無)"}` };
191	    }
192	    if (peer.disabled) {
193	      return { error: `peer「${targetBot}」設定不完整（${peer.disabledReason ?? "缺必填欄位"}），已 disabled` };
194	    }
195	    return { username: peer.botUsername ?? "", mirrorGroupId: peer.groupChatId || cfg.groupChatId };
196	  }
197	  return { username: cfg.targetBotUsername, mirrorGroupId: cfg.groupChatId };
198	}
