369	/** Poll Redis for incoming messages. */
370	async function poll(): Promise<void> {
371	  if (!cfg || !bot) return;
372	  const key = redisKey(cfg.botName);
373	  try {
374	    const { result } = await redisCommand(["RPOP", key]);
375	    if (result === null || typeof result !== "string") {
376	      idleCount++;
377	      if (idleCount >= IDLE_MAX && pollTimer) {
378	        clearInterval(pollTimer);
379	        pollTimer = null;
380	        console.log(`[relay] high-freq poller stopped after ${IDLE_MAX} idle cycles`);
381	      }
382	      return;
383	    }
384	    idleCount = 0;
385	    ensurePollerRunning();
386	    const msg: RelayMessage = JSON.parse(result);
387	    // Hop guard（Q7）：缺欄位視為 1（舊版 peer）。
388	    if ((msg.hop ?? 1) > MAX_HOP) {
389	      console.warn(`[relay] hop limit exceeded（from=${msg.from}, hop=${msg.hop}），拒收`);
390	      return;
391	    }
392	    // Dedup: skip if already received via telegram bot-to-bot
393	    if (isDuplicate(msg.from, msg.text)) {
394	      console.log(`[relay] dedup: skipping redis message from "${msg.from}"`);
395	      return;
396	    }
397	    console.log(`[relay] ✓ received via REDIS from "${msg.from}"`);
398	    if (onIncoming) onIncoming(msg);
399	  } catch (err) {
400	    console.error("[relay] poll error:", err);
401	  }
402	}
