404	/** Initialize relay (registers config + handler). Poller activates on demand. */
405	export function startRelayPoller(
406	  botInstance: Bot,
407	  relayConfig: RelayConfig,
408	  handler: (msg: RelayMessage) => void,
409	): void {
410	  cfg = relayConfig;
411	  bot = botInstance;
412	  onIncoming = handler;
413	  if (pollTimer) { clearInterval(pollTimer); pollTimer = null; }
414	  if (heartbeatTimer) { clearInterval(heartbeatTimer); heartbeatTimer = null; }
415	  // Skip Redis polling entirely when transport is telegram-only.
416	  if (relayConfig.transport === "telegram") {
417	    console.log(`[relay] ready - transport=telegram (${describeRelayTransport(relayConfig.transport)}), Redis poller intentionally disabled`);
418	    return;
419	  }
420	  // Low-freq heartbeat: check for unsolicited incoming every 30s.
421	  heartbeatTimer = setInterval(() => {
422	    if (!pollTimer) poll(); // only if high-freq poller is not running
423	  }, HEARTBEAT_MS);
424	  // One immediate poll to drain anything queued while offline.
425	  poll();
426	  console.log(`[relay] ready - heartbeat every ${HEARTBEAT_MS / 1000}s, high-freq poller on demand (key="${redisKey(cfg.botName)}")`);
427	}
428	
429	export function stopRelayPoller(): void {
430	  if (pollTimer) {
431	    clearInterval(pollTimer);
432	    pollTimer = null;
433	  }
434	  if (heartbeatTimer) {
435	    clearInterval(heartbeatTimer);
436	    heartbeatTimer = null;
437	  }
438	}
