440	/** Quick connectivity test - SET + GET + DEL a test key.
441	 * 注意：不碰 module-global cfg——舊版會把運行中 poller 的設定永久替換掉。 */
442	export async function testRedisConnection(relayConfig: RelayConfig): Promise<boolean> {
443	  try {
444	    await redisCommand(["SET", "relay:_ping", "pong", "EX", "10"], relayConfig);
445	    const { result } = await redisCommand(["GET", "relay:_ping"], relayConfig);
446	    await redisCommand(["DEL", "relay:_ping"], relayConfig);
447	    return result === "pong";
448	  } catch (err) {
449	    console.error("[relay] connection test failed:", err);
450	    return false;
451	  }
452	}
