454	// ─── Dedup for "both" mode ─────────────────────────────────────────────────
455	const recentHashes = new Set<string>();
456	const DEDUP_TTL_MS = 10_000;
457	
458	function dedupKey(from: string, text: string): string {
459	  // 全文 sha1：舊版只取前 100 字，連續兩則前綴相同、後段才分歧的訊息
460	  // （如 [RELAY_RESULT] JSON，id 在 100 字後）會被誤判重複靜默丟棄。
461	  return `${from}:${createHash("sha1").update(text).digest("hex")}`;
462	}
463	
464	/** Returns true if this message is a duplicate (already seen recently). */
465	export function isDuplicate(from: string, text: string): boolean {
466	  const key = dedupKey(from, text);
467	  if (recentHashes.has(key)) return true;
468	  recentHashes.add(key);
469	  setTimeout(() => recentHashes.delete(key), DEDUP_TTL_MS);
470	  return false;
471	}
472	
473	// ─── Telegram bot-to-bot incoming handler ──────────────────────────────────
474	// 兩種格式都認（Q7）：新 `[RELAY:name:hop]`、舊 `[RELAY:name]`（hop 視為 1）。
475	const RELAY_PREFIX_RE = /^\[RELAY:([^\]:]+?)(?::(\d+))?\]\s*/;
476	
477	export interface ParsedBotRelay {
478	  from: string;
479	  text: string;
480	  hop: number;
481	}
482	
483	/** Parse an incoming bot message. Returns null if not a relay message. */
484	export function parseBotRelayMessage(rawText: string): ParsedBotRelay | null {
485	  const m = RELAY_PREFIX_RE.exec(rawText);
486	  if (!m) return null;
487	  const hop = m[2] ? Math.max(1, Number(m[2])) : 1;
488	  return { from: m[1], text: rawText.slice(m[0].length), hop };
489	}
490	
491	/** Get the registered incoming handler (set by startRelayPoller). */
492	export function getRelayHandler(): ((msg: RelayMessage) => void) | null {
493	  return onIncoming;
494	}
495	
496	// ─── Structured Delegation Protocol ────────────────────────────────────────
497	export const DELEGATE_PREFIX = "[RELAY_DELEGATE]";
498	export const RESULT_PREFIX = "[RELAY_RESULT]";
499	
500	export interface DelegatePayload {
501	  id: string;          // correlation_id
502	  goal: string;
503	  context?: string;
504	  maxTurns?: number;
505	}
506	
507	export interface ResultPayload {
508	  id: string;          // correlation_id matching the delegation
509	  status: "done" | "failed" | "timeout";
510	  summary: string;
511	}
512	
513	/** Send a structured delegation request via relay. */
514	export async function sendRelayDelegate(targetBot: string, payload: DelegatePayload, hop: number = 1): Promise<RelaySendResult> {
515	  const text = `${DELEGATE_PREFIX} ${JSON.stringify(payload)}`;
516	  return sendRelay(targetBot, text, hop);
517	}
518	
519	/** Send a structured result back via relay. */
520	export async function sendRelayResult(targetBot: string, payload: ResultPayload): Promise<RelaySendResult> {
521	  const text = `${RESULT_PREFIX} ${JSON.stringify(payload)}`;
522	  return sendRelay(targetBot, text);
523	}
524	
525	/** Parse incoming relay text — returns typed payload or null (plain message). */
526	export function parseRelayPayload(text: string): 
527	  | { type: "delegate"; payload: DelegatePayload }
528	  | { type: "result"; payload: ResultPayload }
529	  | null {
530	  if (text.startsWith(DELEGATE_PREFIX)) {
531	    try {
532	      const json = JSON.parse(text.slice(DELEGATE_PREFIX.length).trim());
533	      return { type: "delegate", payload: json as DelegatePayload };
534	    } catch { return null; }
535	  }
