/**
 * Bot-to-Bot Relay — dual transport: Upstash Redis + Telegram bot-to-bot.
 *
 * Architecture:
 *   sendRelay(msg) -> transport switch:
 *     "redis"    -> LPUSH to Redis list "relay:<targetBot>"
 *     "telegram" -> bot.api.sendMessage(@targetBotUsername, text)
 *     "both"     -> telegram first, redis as fallback
 *   + sendMessage to group (mirror)
 *
 *   Incoming:
 *     Redis poller -> RPOP from "relay:<myName>" -> inject handler
 *     Bot handler  -> from.is_bot + allowedBotIds -> inject handler
 *
 * Redis-only incoming relay messages are mirrored by commands/relay.ts after
 * transport de-duplication. Telegram relay uses sender-side group mirrors so
 * each conversational message appears once in the shared group.
 */
import { stat } from "node:fs/promises";
import { createHash } from "node:crypto";
import path from "node:path";
import { InputFile, type Bot } from "grammy";
import { config } from "./config.js";
import {
  getRelayPeer, listRelayPeerNames, relayPeersFileExists,
} from "./relayPeers.js";

export type RelayTransport = "redis" | "telegram" | "both";

/** 環路防護上限（Q7）：hop > MAX_HOP 拒發/拒收。 */
export const MAX_HOP = 3;

export type RelaySendResult =
  | { ok: true; transport: "telegram" | "redis" }
  | { ok: false; error: string };

export interface RelayConfig {
  redisUrl: string;
  redisToken: string;
  groupChatId: number;
  botName: string;
  transport: RelayTransport;
  targetBotUsername: string; // e.g. "@RK_AI_Codex_bot" for telegram transport
  /** 多 peer 對照表：peer 名 → Telegram username。未設定沿用 targetBotUsername。 */
  peerUsernames?: Record<string, string>;
  maxConsecutiveTurns: number;
}

interface RelayMessage {
  from: string;
  text: string;
  ts: string;
  /** re-relay 計數（Q7）；缺欄位視為 1（容忍舊版 peer）。 */
  hop?: number;
}

let cfg: RelayConfig | null = null;
let bot: Bot | null = null;
let pollTimer: ReturnType<typeof setInterval> | null = null;
let heartbeatTimer: ReturnType<typeof setInterval> | null = null;
let onIncoming: ((msg: RelayMessage) => void) | null = null;
let idleCount = 0;
const IDLE_MAX = 40; // ~2 min at 3s interval -> auto-stop
const HEARTBEAT_MS = 30_000; // low-freq check for unsolicited incoming
const IMG_EXT = new Set([".jpg", ".jpeg", ".png", ".gif", ".webp", ".bmp"]);
const PHOTO_MAX_BYTES = 10 * 1024 * 1024;

export interface RelayRuntimeStatus {
  configured: boolean;
  botName: string | null;
  transport: RelayTransport | null;
  transportLabel: string;
  groupChatId: number | null;
  targetBotUsername: string | null;
  redisConfigured: boolean;
  telegramConfigured: boolean;
  redisPollerExpected: boolean;
  redisPollerActive: boolean;
  heartbeatActive: boolean;
  maxConsecutiveTurns: number | null;
}

export function describeRelayTransport(transport: RelayTransport | null): string {
  if (transport === "redis") return "redis only";
  if (transport === "telegram") return "telegram only";
  if (transport === "both") return "telegram primary + redis fallback";
  return "not configured";
}

export function getRelayRuntimeStatus(): RelayRuntimeStatus {
  if (!cfg) {
    return {
      configured: false,
      botName: null,
      transport: null,
      transportLabel: describeRelayTransport(null),
      groupChatId: null,
      targetBotUsername: null,
      redisConfigured: false,
      telegramConfigured: false,
      redisPollerExpected: false,
      redisPollerActive: false,
      heartbeatActive: false,
      maxConsecutiveTurns: null,
    };
  }
  const redisConfigured = !!(cfg.redisUrl && cfg.redisToken);
  const telegramConfigured = !!cfg.targetBotUsername;
  return {
    configured: true,
    botName: cfg.botName,
    transport: cfg.transport,
    transportLabel: describeRelayTransport(cfg.transport),
    groupChatId: cfg.groupChatId,
    targetBotUsername: cfg.targetBotUsername || null,
    redisConfigured,
    telegramConfigured,
    redisPollerExpected: cfg.transport !== "telegram" && redisConfigured,
    redisPollerActive: !!pollTimer,
    heartbeatActive: !!heartbeatTimer,
    maxConsecutiveTurns: cfg.maxConsecutiveTurns,
  };
}

function redisKey(target: string): string {
  return `relay:${target}`;
}

function isUnderAllowedRoot(abs: string): boolean {
  const roots = [config.sessionCwd, ...config.sendFileRoots];
  const normAbs = path.resolve(abs).toLowerCase();
  return roots.some((root) => {
    const r = path.resolve(root).toLowerCase().replace(/[\\/]+$/, "");
    if (normAbs === r) return true;
    return normAbs.startsWith(r + "\\") || normAbs.startsWith(r + "/");
  });
}

async function redisCommand(command: string[], c: RelayConfig | null = cfg): Promise<{ result: unknown }> {
  if (!c) throw new Error("Relay not initialized");
  const res = await fetch(c.redisUrl, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${c.redisToken}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(command),
  });
  if (!res.ok) {
    const body = await res.text();
    throw new Error(`Redis ${command[0]} failed: ${res.status} ${body}`);
  }
  return res.json() as Promise<{ result: unknown }>;
}

/**
 * Resolve a relay peer 的 Telegram username（telegram transport 用）。
 * 沒設 peerUsernames map → 沿用單一 targetBotUsername（既有單 peer 行為）；
 * 有設 map 但 peer 不在其中 → null（拒走 telegram，避免寫給 peer B 的訊息
 * 靜默誤投給預設 bot；transport=both 時自然 fallback 到 redis 正確投遞）。
 */
function resolvePeerUsername(targetBot: string): string | null {
  if (!cfg) return null;
  const map = cfg.peerUsernames;
  if (map && Object.keys(map).length > 0) {
    return map[targetBot] ?? null;
  }
  return cfg.targetBotUsername || null;
}

/** Start polling if not already running. */
export function ensurePollerRunning(): void {
  if (pollTimer || !cfg) return;
  idleCount = 0;
  pollTimer = setInterval(poll, 3000);
  console.log(`[relay] poller activated`);
}

/**
 * Resolve outgoing destination for a target peer name.
 * peers.json 存在 → 查 peer config（未知/disabled 回 error）；
 * 不存在 → legacy 單 peer env mode（沿用 RELAY_TARGET_BOT_USERNAME）。
 */
function resolveOutgoing(targetBot: string): { username: string; mirrorGroupId: number } | { error: string } {
  if (!cfg) return { error: "Relay not initialized" };
  if (relayPeersFileExists()) {
    const peer = getRelayPeer(targetBot);
    if (!peer) {
      const names = listRelayPeerNames();
      return { error: `未知 peer「${targetBot}」，可用：${names.join("、") || "(無)"}` };
    }
    if (peer.disabled) {
      return { error: `peer「${targetBot}」設定不完整（${peer.disabledReason ?? "缺必填欄位"}），已 disabled` };
    }
    return { username: peer.botUsername ?? "", mirrorGroupId: peer.groupChatId || cfg.groupChatId };
  }
  return { username: cfg.targetBotUsername, mirrorGroupId: cfg.groupChatId };
}

/**
 * Send a message to another bot via configured transport + mirror to group.
 * @param hop re-relay 計數（Q7）：本地發起=1；轉發收到的內容時傳 incoming+1。
 */
export async function sendRelay(targetBot: string, text: string, hop: number = 1): Promise<RelaySendResult> {
  if (!cfg || !bot) return { ok: false, error: "Relay not configured" };
  if (process.env.RELAY_PAUSED === "true") {
    console.log(`[relay] RELAY_PAUSED — blocked outgoing to "${targetBot}"`);
    return { ok: false, error: "RELAY_PAUSED" };
  }
