  if (targetBot === cfg.botName) {
    console.warn(`[relay] blocked self-send (target="${targetBot}"), text: ${text.slice(0, 80)}`);
    return { ok: false, error: `不可 relay 給自己（${targetBot}）` };
  }
  // Guard: skip empty or placeholder-only messages (e.g. "...", "…").
  const trimmed = text.replace(/[.\s…]+/g, "");
  if (!trimmed) {
    console.warn(`[relay] blocked empty/placeholder relay to "${targetBot}": "${text.slice(0, 40)}"`);
    return { ok: false, error: "空白訊息" };
  }
  // Guard: hop limit（Q7）— 拒發超限的 re-relay。
  if (hop > MAX_HOP) {
    console.warn(`[relay] hop limit exceeded on send (target="${targetBot}", hop=${hop})`);
    return { ok: false, error: `relay hop limit exceeded（hop=${hop} > ${MAX_HOP}）` };
  }

