/** Poll Redis for incoming messages. */
async function poll(): Promise<void> {
  if (!cfg || !bot) return;
  const key = redisKey(cfg.botName);
  try {
    const { result } = await redisCommand(["RPOP", key]);
    if (result === null || typeof result !== "string") {
      idleCount++;
      if (idleCount >= IDLE_MAX && pollTimer) {
        clearInterval(pollTimer);
        pollTimer = null;
        console.log(`[relay] high-freq poller stopped after ${IDLE_MAX} idle cycles`);
      }
      return;
    }
    idleCount = 0;
    ensurePollerRunning();
    const msg: RelayMessage = JSON.parse(result);
    // Hop guard（Q7）：缺欄位視為 1（舊版 peer）。
    if ((msg.hop ?? 1) > MAX_HOP) {
      console.warn(`[relay] hop limit exceeded（from=${msg.from}, hop=${msg.hop}），拒收`);
      return;
    }
    // Dedup: skip if already received via telegram bot-to-bot
    if (isDuplicate(msg.from, msg.text)) {
      console.log(`[relay] dedup: skipping redis message from "${msg.from}"`);
      return;
    }
    console.log(`[relay] ✓ received via REDIS from "${msg.from}"`);
    if (onIncoming) onIncoming(msg);
  } catch (err) {
    console.error("[relay] poll error:", err);
  }
}

/** Initialize relay (registers config + handler). Poller activates on demand. */
export function startRelayPoller(
  botInstance: Bot,
  relayConfig: RelayConfig,
  handler: (msg: RelayMessage) => void,
): void {
  cfg = relayConfig;
  bot = botInstance;
  onIncoming = handler;
  if (pollTimer) { clearInterval(pollTimer); pollTimer = null; }
  if (heartbeatTimer) { clearInterval(heartbeatTimer); heartbeatTimer = null; }
  // Skip Redis polling entirely when transport is telegram-only.
  if (relayConfig.transport === "telegram") {
    console.log(`[relay] ready - transport=telegram (${describeRelayTransport(relayConfig.transport)}), Redis poller intentionally disabled`);
    return;
  }
  // Low-freq heartbeat: check for unsolicited incoming every 30s.
  heartbeatTimer = setInterval(() => {
    if (!pollTimer) poll(); // only if high-freq poller is not running
  }, HEARTBEAT_MS);
  // One immediate poll to drain anything queued while offline.
  poll();
  console.log(`[relay] ready - heartbeat every ${HEARTBEAT_MS / 1000}s, high-freq poller on demand (key="${redisKey(cfg.botName)}")`);
}

export function stopRelayPoller(): void {
  if (pollTimer) {
    clearInterval(pollTimer);
    pollTimer = null;
  }
  if (heartbeatTimer) {
    clearInterval(heartbeatTimer);
    heartbeatTimer = null;
  }
}

/** Quick connectivity test - SET + GET + DEL a test key.
 * 注意：不碰 module-global cfg——舊版會把運行中 poller 的設定永久替換掉。 */
export async function testRedisConnection(relayConfig: RelayConfig): Promise<boolean> {
  try {
    await redisCommand(["SET", "relay:_ping", "pong", "EX", "10"], relayConfig);
    const { result } = await redisCommand(["GET", "relay:_ping"], relayConfig);
    await redisCommand(["DEL", "relay:_ping"], relayConfig);
    return result === "pong";
  } catch (err) {
    console.error("[relay] connection test failed:", err);
    return false;
  }
}

// ─── Dedup for "both" mode ─────────────────────────────────────────────────
const recentHashes = new Set<string>();
const DEDUP_TTL_MS = 10_000;

function dedupKey(from: string, text: string): string {
  // 全文 sha1：舊版只取前 100 字，連續兩則前綴相同、後段才分歧的訊息
  // （如 [RELAY_RESULT] JSON，id 在 100 字後）會被誤判重複靜默丟棄。
  return `${from}:${createHash("sha1").update(text).digest("hex")}`;
}

/** Returns true if this message is a duplicate (already seen recently). */
export function isDuplicate(from: string, text: string): boolean {
  const key = dedupKey(from, text);
  if (recentHashes.has(key)) return true;
  recentHashes.add(key);
  setTimeout(() => recentHashes.delete(key), DEDUP_TTL_MS);
  return false;
}

// ─── Telegram bot-to-bot incoming handler ──────────────────────────────────
// 兩種格式都認（Q7）：新 `[RELAY:name:hop]`、舊 `[RELAY:name]`（hop 視為 1）。
const RELAY_PREFIX_RE = /^\[RELAY:([^\]:]+?)(?::(\d+))?\]\s*/;

export interface ParsedBotRelay {
  from: string;
  text: string;
  hop: number;
}

/** Parse an incoming bot message. Returns null if not a relay message. */
export function parseBotRelayMessage(rawText: string): ParsedBotRelay | null {
  const m = RELAY_PREFIX_RE.exec(rawText);
  if (!m) return null;
  const hop = m[2] ? Math.max(1, Number(m[2])) : 1;
  return { from: m[1], text: rawText.slice(m[0].length), hop };
}

/** Get the registered incoming handler (set by startRelayPoller). */
export function getRelayHandler(): ((msg: RelayMessage) => void) | null {
  return onIncoming;
}

// ─── Structured Delegation Protocol ────────────────────────────────────────
export const DELEGATE_PREFIX = "[RELAY_DELEGATE]";
export const RESULT_PREFIX = "[RELAY_RESULT]";

export interface DelegatePayload {
  id: string;          // correlation_id
  goal: string;
  context?: string;
  maxTurns?: number;
}

export interface ResultPayload {
  id: string;          // correlation_id matching the delegation
  status: "done" | "failed" | "timeout";
  summary: string;
}

/** Send a structured delegation request via relay. */
export async function sendRelayDelegate(targetBot: string, payload: DelegatePayload, hop: number = 1): Promise<RelaySendResult> {
  const text = `${DELEGATE_PREFIX} ${JSON.stringify(payload)}`;
  return sendRelay(targetBot, text, hop);
}

/** Send a structured result back via relay. */
export async function sendRelayResult(targetBot: string, payload: ResultPayload): Promise<RelaySendResult> {
  const text = `${RESULT_PREFIX} ${JSON.stringify(payload)}`;
  return sendRelay(targetBot, text);
}

/** Parse incoming relay text — returns typed payload or null (plain message). */
export function parseRelayPayload(text: string): 
  | { type: "delegate"; payload: DelegatePayload }
  | { type: "result"; payload: ResultPayload }
  | null {
  if (text.startsWith(DELEGATE_PREFIX)) {
    try {
      const json = JSON.parse(text.slice(DELEGATE_PREFIX.length).trim());
      return { type: "delegate", payload: json as DelegatePayload };
    } catch { return null; }
  }
  if (text.startsWith(RESULT_PREFIX)) {
    try {
      const json = JSON.parse(text.slice(RESULT_PREFIX.length).trim());
      return { type: "result", payload: json as ResultPayload };
    } catch { return null; }
  }
  return null;
}

