// Bot-to-Bot Relay via Upstash Redis + Telegram bot-to-bot
relay: (() => {
  const url = (process.env.UPSTASH_REDIS_REST_URL ?? "").trim();
  const token = (process.env.UPSTASH_REDIS_REST_TOKEN ?? "").trim();
  const groupChatId = Number(process.env.RELAY_GROUP_CHAT_ID ?? "0");
  const botName = (process.env.RELAY_BOT_NAME ?? "").trim();
  const transport = (process.env.RELAY_TRANSPORT ?? "redis").trim() as "redis" | "telegram" | "both";
  const targetBotUsername = (process.env.RELAY_TARGET_BOT_USERNAME ?? "").trim();
  // Minimum: need botName + groupChatId + at least one transport configured
  const hasRedis = !!(url && token);
  const hasTelegram = !!targetBotUsername;
  if (!groupChatId || !botName) return null;
  if (!hasRedis && !hasTelegram) return null;
  const maxConsecutiveTurns = Number(process.env.RELAY_MAX_CONSECUTIVE_TURNS) || 3;
  // 多 peer 對照表："小白=@bot_a,小X=@bot_b"。未設定 → telegram 路徑沿用
  // 單一 targetBotUsername（既有行為）；有設定 → 按 peer 名解析 username，
  // 不在表內的 peer 拒走 telegram（避免誤投給預設 bot）。
  const peerUsernames: Record<string, string> = {};
  for (const pair of (process.env.RELAY_PEER_USERNAMES ?? "").split(",")) {
    const eq = pair.indexOf("=");
    if (eq <= 0) continue;
    const name = pair.slice(0, eq).trim();
    const username = pair.slice(eq + 1).trim();
    if (name && username) peerUsernames[name] = username;
  }
  return { redisUrl: url, redisToken: token, groupChatId, botName, maxConsecutiveTurns, transport, targetBotUsername, peerUsernames };
})(),

