#!/usr/bin/env node
/**
 * sync-skills-to-repo.mjs — Copy tracked default-skills FROM local skill dir(s) TO repo.
 * Only syncs skills already in default-skills/ (won't add new ones).
 * Called by .githooks/pre-commit automatically.
 *
 * Scans MULTIPLE candidate skill dirs (not just Kiro) so it keeps working after
 * switching ACP adapter — see wiki [[acp-adapter]]. For each tracked skill, the
 * NEWEST copy (by mtime) across all dirs wins. Priority is only a tiebreak/order;
 * mtime is the real selector, so editing a skill in ~/.claude/skills is picked up
 * even though the repo was seeded from ~/.kiro/skills.
 */
import { readFileSync, writeFileSync, readdirSync, existsSync, mkdirSync, statSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import os from "node:os";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, "..");
const defaultSkillsDir = path.join(repoRoot, "default-skills");
const home = os.homedir();

if (!existsSync(defaultSkillsDir)) process.exit(0);

// Candidate skill dirs. Current adapter's AGENT_CONFIG_DIR/skills first, then the
// known CLI locations. Deduped, existence-checked below.
const candidateDirs = [
  process.env.AGENT_CONFIG_DIR ? path.join(process.env.AGENT_CONFIG_DIR, "skills") : null,
  path.join(home, ".claude", "skills"),
  path.join(home, ".kiro", "skills"),
  path.join(home, ".codex", "skills"),
]
  .filter(Boolean)
  .filter((d, i, a) => a.indexOf(d) === i) // dedupe
  .filter((d) => existsSync(d));

const tracked = readdirSync(defaultSkillsDir, { withFileTypes: true })
  .filter((e) => e.isDirectory())
  .map((e) => e.name);

/** Find the newest SKILL.md for `name` across all candidate dirs. */
function newestSource(name) {
  let best = null;
  for (const dir of candidateDirs) {
    const file = path.join(dir, name, "SKILL.md");
    if (!existsSync(file)) continue;
    const mtime = statSync(file).mtimeMs;
    if (!best || mtime > best.mtime) best = { file, mtime, dir };
  }
  return best;
}

let updated = 0;
for (const name of tracked) {
  const src = newestSource(name);
  if (!src) continue;
  const dstFile = path.join(defaultSkillsDir, name, "SKILL.md");
  const srcContent = readFileSync(src.file, "utf8");
  const dstContent = existsSync(dstFile) ? readFileSync(dstFile, "utf8") : "";
  if (srcContent === dstContent) continue;
  mkdirSync(path.dirname(dstFile), { recursive: true });
  writeFileSync(dstFile, srcContent, "utf8");
  updated++;
}

if (updated > 0) console.log(`[sync-skills] ${updated} skill(s) updated in default-skills/`);
